using System.ComponentModel;
using System.Net;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// Build the IChatClient via MEAI abstraction
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ---------------------------------------------------------------------------
// Tool state
// ---------------------------------------------------------------------------
var notepad = new ResearchNotepad();

using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ---------------------------------------------------------------------------
// Define agent tools
// ---------------------------------------------------------------------------
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
            WebTools.SearchAsync(httpClient, query),
        "SearchWeb",
        "Searches the web for information on a topic and returns a summary of results."),

    AIFunctionFactory.Create(
        ([Description("Full URL of the web page to read")] string url) =>
            WebTools.ReadPageAsync(httpClient, url),
        "ReadWebPage",
        "Fetches and extracts text content from a web page URL for deeper reading."),

    AIFunctionFactory.Create(
        ([Description("Short title for the note")] string title,
         [Description("Detailed content of the note")] string content) =>
            notepad.TakeNote(title, content),
        "TakeNote",
        "Saves a research note. Use this to record every important finding."),

    AIFunctionFactory.Create(
        () => notepad.GetNotes(),
        "GetNotes",
        "Returns all research notes taken so far."),
};

// ---------------------------------------------------------------------------
// Create the agent
// ---------------------------------------------------------------------------
const string instructions = """
    You are a research agent. Your job is to thoroughly research a given topic
    using web searches, take structured notes on your findings, and then produce
    a comprehensive summary.

    Follow this workflow:
    1. Break the topic into 2-3 key subtopics or questions.
    2. Use SearchWeb for each subtopic.
    3. Use ReadWebPage when you need more detail from a specific URL.
    4. Use TakeNote to record every important finding with a descriptive title.
    5. After gathering enough information, call GetNotes to review everything,
       then write a well-organized summary with source URLs.

    Be thorough but concise. Always cite your sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics by searching the web, reading pages, and taking notes.",
    tools: tools,
    loggerFactory: null,
    services: null);

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║         🔍  AI Research Agent            ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n📖  Researching: {topic}\n");

var session = await agent.CreateSessionAsync("research-session");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════════");

var notes = notepad.GetNotes();
if (notes.Count > 0)
{
    Console.WriteLine($"\n📝  {notes.Count} research note(s) were recorded.");
}

// ===========================================================================
// Web tools
// ===========================================================================
static class WebTools
{
    public static async Task<string> SearchAsync(HttpClient http, string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;
            var results = new List<string>();

            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"[{abstractSource}] {abstractText}\nSource: {abstractUrl}");

            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var firstUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {firstUrl.GetString()}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No direct results for '{query}'. Try different keywords or use ReadWebPage with a known URL.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    public static async Task<string> ReadPageAsync(HttpClient http, string url)
    {
        try
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) ||
                (uri.Scheme != "http" && uri.Scheme != "https"))
            {
                return "Invalid URL. Provide an http or https URL.";
            }

            using var request = new HttpRequestMessage(HttpMethod.Get, uri);
            request.Headers.Add("Accept", "text/html");

            using var response = await http.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();

            // Strip scripts, styles, and HTML tags
            var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<[^>]+>", " ");
            text = WebUtility.HtmlDecode(text);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLen = 3000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "… [truncated]";

            return $"Content from {url}:\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to read page: {ex.Message}";
        }
    }
}

// ===========================================================================
// Research notepad
// ===========================================================================
class ResearchNotepad
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public string TakeNote(string title, string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        return $"✅ Note saved: \"{title}\" ({_notes.Count} total)";
    }

    public IReadOnlyList<string> GetNotes()
    {
        return _notes
            .Select((n, i) => $"[Note {i + 1}] {n.Title} ({n.Timestamp:u})\n{n.Content}")
            .ToList();
    }
}

