+            return $"Search failed: {ex.Message}";
+        }
+    }
+
+    public static async Task<string> ReadPageAsync(HttpClient http, string url)
+    {
+        try
+        {
+            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) ||
+                (uri.Scheme != "http" && uri.Scheme != "https"))
+            {
+                return "Invalid URL. Provide an http or https URL.";
+            }
+
+            using var request = new HttpRequestMessage(HttpMethod.Get, uri);
+            request.Headers.Add("Accept", "text/html");
+
+            using var response = await http.SendAsync(request);
+            response.EnsureSuccessStatusCode();
+
+            var html = await response.Content.ReadAsStringAsync();
+
+            // Strip scripts, styles, and HTML tags
+            var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
+            text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
+            text = Regex.Replace(text, @"<[^>]+>", " ");
+            text = WebUtility.HtmlDecode(text);
+            text = Regex.Replace(text, @"\s+", " ").Trim();
+
+            const int maxLen = 3000;
+            if (text.Length > maxLen)
+                text = text[..maxLen] + "… [truncated]";
+
+            return $"Content from {url}:\n{text}";
+        }
+        catch (Exception ex)
+        {
+            return $"Failed to read page: {ex.Message}";
+        }
+    }
+}
