+// ===========================================================================
+// Research notepad
+// ===========================================================================
+class ResearchNotepad
+{
+    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];
+
+    public string TakeNote(string title, string content)
+    {
+        _notes.Add((title, content, DateTime.UtcNow));
+        return $"✅ Note saved: \"{title}\" ({_notes.Count} total)";
+    }
+
+    public IReadOnlyList<string> GetNotes()
+    {
+        return _notes
+            .Select((n, i) => $"[Note {i + 1}] {n.Title} ({n.Timestamp:u})\n{n.Content}")
+            .ToList();
+    }
+}
